import java.util.*;
import java.io.*;

class Main {
    public static int solution(int h, int w, int[] horizontalCuts, int[] verticalCuts) {
        final int MOD = 1000000007;

        // Add boundary cuts and sort
        List<Integer> hCuts = new ArrayList<>();
        hCuts.add(0);
        for (int cut : horizontalCuts) hCuts.add(cut);
        hCuts.add(h);
        Collections.sort(hCuts);

        List<Integer> vCuts = new ArrayList<>();
        vCuts.add(0);
        for (int cut : verticalCuts) vCuts.add(cut);
        vCuts.add(w);
        Collections.sort(vCuts);

        // Find maximum gap between consecutive cuts
        long maxHeight = 0;
        for (int i = 1; i < hCuts.size(); i++) {
            maxHeight = Math.max(maxHeight, hCuts.get(i) - hCuts.get(i-1));
        }

        long maxWidth = 0;
        for (int i = 1; i < vCuts.size(); i++) {
            maxWidth = Math.max(maxWidth, vCuts.get(i) - vCuts.get(i-1));
        }

        return (int)((maxHeight * maxWidth) % MOD);
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int h = Integer.parseInt(br.readLine().trim());
        int w = Integer.parseInt(br.readLine().trim());

        String hCutsLine = br.readLine().trim();
        int[] horizontalCuts;
        if (hCutsLine.equals("[]")) {
            horizontalCuts = new int[0];
        } else {
            horizontalCuts = Arrays.stream(hCutsLine.substring(1, hCutsLine.length()-1).split(","))
                                         .mapToInt(s -> Integer.parseInt(s.trim())).toArray();
        }

        String vCutsLine = br.readLine().trim();
        int[] verticalCuts;
        if (vCutsLine.equals("[]")) {
            verticalCuts = new int[0];
        } else {
            verticalCuts = Arrays.stream(vCutsLine.substring(1, vCutsLine.length()-1).split(","))
                                       .mapToInt(s -> Integer.parseInt(s.trim())).toArray();
        }

        System.out.println(solution(h, w, horizontalCuts, verticalCuts));
    }
}

