package main

import (
    "bufio"
    "encoding/json"
    "fmt"
    "os"
    "sort"
    "strconv"
    "strings"
)

func solution(h int, w int, horizontalCuts []int, verticalCuts []int) int {
    const MOD = 1000000007

    // Add boundary cuts and sort
    hCuts := append([]int{0}, horizontalCuts...)
    hCuts = append(hCuts, h)
    sort.Ints(hCuts)

    vCuts := append([]int{0}, verticalCuts...)
    vCuts = append(vCuts, w)
    sort.Ints(vCuts)

    // Find maximum gap between consecutive cuts
    maxHeight := 0
    for i := 1; i < len(hCuts); i++ {
        gap := hCuts[i] - hCuts[i-1]
        if gap > maxHeight {
            maxHeight = gap
        }
    }

    maxWidth := 0
    for i := 1; i < len(vCuts); i++ {
        gap := vCuts[i] - vCuts[i-1]
        if gap > maxWidth {
            maxWidth = gap
        }
    }

    return (int64(maxHeight) * int64(maxWidth)) % MOD
}

func main() {
    reader := bufio.NewReader(os.Stdin)

    hLine, _ := reader.ReadString('\n')
    h, _ := strconv.Atoi(strings.TrimSpace(hLine))

    wLine, _ := reader.ReadString('\n')
    w, _ := strconv.Atoi(strings.TrimSpace(wLine))

    hCutsLine, _ := reader.ReadString('\n')
    var horizontalCuts []int
    json.Unmarshal([]byte(strings.TrimSpace(hCutsLine)), &horizontalCuts)

    vCutsLine, _ := reader.ReadString('\n')
    var verticalCuts []int
    json.Unmarshal([]byte(strings.TrimSpace(vCutsLine)), &verticalCuts)

    result := solution(h, w, horizontalCuts, verticalCuts)
    fmt.Println(result)
}

