#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int solution(int h, int w, int* horizontalCuts, int hSize, int* verticalCuts, int vSize) {
    const int MOD = 1000000007;

    // Add boundary cuts and sort
    int* hCuts = (int*)malloc((hSize + 2) * sizeof(int));
    hCuts[0] = 0;
    for (int i = 0; i < hSize; i++) {
        hCuts[i + 1] = horizontalCuts[i];
    }
    hCuts[hSize + 1] = h;
    qsort(hCuts, hSize + 2, sizeof(int), compare);

    int* vCuts = (int*)malloc((vSize + 2) * sizeof(int));
    vCuts[0] = 0;
    for (int i = 0; i < vSize; i++) {
        vCuts[i + 1] = verticalCuts[i];
    }
    vCuts[vSize + 1] = w;
    qsort(vCuts, vSize + 2, sizeof(int), compare);

    // Find maximum gap between consecutive cuts
    long long maxHeight = 0;
    for (int i = 1; i < hSize + 2; i++) {
        long long gap = hCuts[i] - hCuts[i-1];
        if (gap > maxHeight) maxHeight = gap;
    }

    long long maxWidth = 0;
    for (int i = 1; i < vSize + 2; i++) {
        long long gap = vCuts[i] - vCuts[i-1];
        if (gap > maxWidth) maxWidth = gap;
    }

    free(hCuts);
    free(vCuts);

    return (maxHeight * maxWidth) % MOD;
}

int main() {
    int h, w;
    scanf("%d", &h);
    scanf("%d", &w);

    int horizontalCuts[100], verticalCuts[100];
    int hSize = 0, vSize = 0;

    char line[1000];
    scanf(" %s", line);
    if (strcmp(line, "[]") != 0) {
        char* token = strtok(line + 1, ",]");
        while (token != NULL) {
            horizontalCuts[hSize++] = atoi(token);
            token = strtok(NULL, ",]");
        }
    }

    scanf(" %s", line);
    if (strcmp(line, "[]") != 0) {
        char* token = strtok(line + 1, ",]");
        while (token != NULL) {
            verticalCuts[vSize++] = atoi(token);
            token = strtok(NULL, ",]");
        }
    }

    printf("%d\n", solution(h, w, horizontalCuts, hSize, verticalCuts, vSize));
    return 0;
}

